/**
 * CONTENT BRIEF VALIDATOR
 * 
 * Validates and enriches content generation request with defaults
 * and SEO requirements.
 */

const input = $input.item.json.body || $input.item.json;

// Validate required field
if (!input.topic) {
  throw new Error('topic is required');
}

// Create comprehensive content brief
const contentBrief = {
  // User-provided data
  topic: input.topic,
  keywords: input.keywords || [],
  wordCount: input.wordCount || 1000,
  tone: input.tone || 'professional',
  contentType: input.contentType || 'blog',
  includeImages: input.includeImages !== false, // default true
  seoOptimize: input.seoOptimize !== false, // default true

  // Generated metadata
  requestId: `content_${Date.now()}`,
  timestamp: new Date().toISOString(),

  // SEO parameters
  seo: {
    targetKeywords: input.keywords || [],
    metaDescriptionLength: 155,
    titleLength: 60,
    headerStructure: ['H2', 'H3'],
    keywordDensity: '1-2%'
  },

  // Content structure requirements
  structure: {
    introduction: true,
    sections: Math.ceil(input.wordCount / 300), // ~300 words per section
    conclusion: true,
    callToAction: true
  }
};

return { json: contentBrief };

/**
 * TAG PROCESSOR
 * 
 * Processes suggested tags and creates them in WordPress if needed.
 */

const content = $('Parse & Validate Content').item.json;
const wordpressSiteUrl = $('Validate Content Brief').item.json.wordpressSiteUrl;

// Prepare tags for WordPress
const tags = content.suggestedTags.map(tag => ({
  name: tag,
  slug: tag.toLowerCase().replace(/[^a-z0-9]+/g, '-')
}));

return {
  json: {
    tags,
    wordpressSiteUrl,
    postId: $('Create WordPress Post').item.json.id
  }
};

/**
 * SUCCESS RESPONSE GENERATOR
 * 
 * Creates comprehensive success response with all details.
 */

const content = $('Parse & Validate Content').item.json;
const post = $('Create WordPress Post').item.json;
const brief = $('Validate Content Brief').item.json;

const response = {
  success: true,
  message: 'Content generated and posted successfully!',

  content: {
    title: content.title,
    wordCount: content.meta.actualWordCount,
    readingTime: content.readingTime,
    seoScore: content.seoScore
  },

  wordpress: {
    postId: post.id,
    postUrl: post.link,
    editUrl: post.link.replace(/\/?$/, '') + '/wp-admin/post.php?post=' + post.id + '&action=edit',
    status: 'draft',
    featuredImage: post.featured_media > 0
  },

  seo: {
    metaDescription: content.metaDescription,
    tags: content.suggestedTags,
    keywords: brief.keywords
  },

  performance: {
    requestId: brief.requestId,
    generatedAt: content.meta.generatedAt,
    processingTime: '~2-3 minutes'
  },

  nextSteps: [
    'Review the draft post in WordPress',
    'Check SEO optimization',
    'Add any custom modifications',
    'Publish when ready'
  ]
};

return { json: response };

// Get the response from Groq
const groqResponse = $input.item.json;

// Extract the AI message from Groq's response structure
const aiMessage = groqResponse.choices[0].message.content;

// Parse the JSON content
let content;
try {
  // Remove any markdown code blocks if present
  const cleanedMessage = aiMessage.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parse JSON
  content = JSON.parse(cleanedMessage);

} catch (error) {
  // If parsing fails, create a basic structure
  console.log('JSON parse error:', error);
  content = {
    title: "Generated Content",
    content: aiMessage,
    excerpt: aiMessage.substring(0, 150),
    metaDescription: aiMessage.substring(0, 155),
    suggestedTags: ["wordpress", "blog"],
    readingTime: "3 minutes",
    seoScore: "Needs review"
  };
}

// Validate required fields
if (!content.title || !content.content) {
  throw new Error('AI response missing required fields (title or content)');
}

// Return formatted content
return {
  json: {
    title: content.title,
    content: content.content,
    excerpt: content.excerpt || content.content.substring(0, 150),
    metaDescription: content.metaDescription || content.excerpt?.substring(0, 155),
    suggestedTags: content.suggestedTags || [],
    readingTime: content.readingTime || "3 minutes",
    seoScore: content.seoScore || "Good",
    wordCount: content.content.split(' ').length
  }
};
